inline:<div id="sequence-builder-root">
  <style>
    #sequence-builder-root { background: #0A0A12; color: #00F2FF; font-family: 'JetBrains Mono', monospace; padding: 16px; }
    .c2-grid { display: grid; grid-template-columns: repeat(auto-fill, 50px); gap: 8px; }
    .c2-cell { width: 50px; height: 50px; border: 1px solid #00F2FF; display: flex; align-items: center; justify-content: center; cursor: pointer; }
    .c2-cell.active { background: #FF00E5; color: #0A0A12; }
    .c2-reduced { display: block; }
  </style>
  <div class="c2-grid" id="sequence-builder-root-grid"></div>
  <script>
    let state = [];
    const pair = { 'A': 'T', 'T': 'A', 'C': 'G', 'G': 'C' };
    window.c2_mount = () => {
      const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
      const grid = document.getElementById('sequence-builder-root-grid');
      const target = "GATTACA";
      state = new Array(target.length).fill(null);
      target.split('').forEach((b, i) => {
        const cell = document.createElement('div');
        cell.className = 'c2-cell';
        cell.textContent = '?';
        cell.onclick = () => {
          const bases = ['A', 'T', 'C', 'G'];
          const curIdx = bases.indexOf(cell.textContent);
          cell.textContent = bases[(curIdx + 1) % 4] || 'A';
          state[i] = cell.textContent;
        };
        grid.appendChild(cell);
      });
    };
    window.c2_validateSequence = () => {
      const cells = document.querySelectorAll('.c2-cell');
      const target = "GATTACA";
      cells.forEach((c, i) => {
        const correctPair = pair[target[i]];
        c.style.borderColor = c.textContent === correctPair ? '#00F2FF' : '#FF00E5';
      });
    };
    window.c2_resetBuilder = () => { document.getElementById('sequence-builder-root-grid').innerHTML = ''; window.c2_mount(); };
    window.c2_destroy = () => { state = []; };
  </script>
</div>
